QBANK["AR"] = [{"q":"A store sells pencils in boxes of 12. If a teacher buys 8 boxes, how many pencils does she have in total?","c":["96","84","104","120"],"a":0,"e":"12 pencils per box times 8 boxes = 96 pencils. The answer is 96."},{"q":"A car travels 240 miles in 4 hours. What is its average speed in miles per hour?","c":["48 mph","56 mph","60 mph","64 mph"],"a":2,"e":"Average speed = distance / time = 240 / 4 = 60 mph."},{"q":"A shirt originally priced at $40 is on sale for 25% off. What is the sale price?","c":["$10","$30","$35","$32"],"a":1,"e":"25% of $40 = $10 discount. $40 - $10 = $30 sale price."},{"q":"If 3/4 of a class of 28 students passed a test, how many students passed?","c":["7","18","24","21"],"a":3,"e":"3/4 of 28 = (28 / 4) x 3 = 7 x 3 = 21 students passed."},{"q":"A recipe calls for 2 1/2 cups of flour. If you make a triple batch, how many cups of flour do you need?","c":["5 cups","6 cups","7 1/2 cups","8 cups"],"a":2,"e":"2.5 cups x 3 = 7.5 cups, which is 7 1/2 cups."},{"q":"What is 15% of 80?","c":["8","12","16","15"],"a":1,"e":"15% = 0.15. 0.15 x 80 = 12."},{"q":"A worker earns $18 per hour and works 35 hours in a week. How much does she earn that week?","c":["$540","$630","$700","$590"],"a":1,"e":"$18 x 35 = $630 for the week."},{"q":"Two numbers have a sum of 50. If one number is 18, what is the other?","c":["68","32","22","42"],"a":1,"e":"50 - 18 = 32. The other number is 32."},{"q":"A rectangular room is 12 feet long and 9 feet wide. What is its area?","c":["21 sq ft","42 sq ft","108 sq ft","96 sq ft"],"a":2,"e":"Area = length x width = 12 x 9 = 108 square feet."},{"q":"A water tank holds 60 gallons and is 3/5 full. How many gallons of water are in it?","c":["20 gallons","36 gallons","45 gallons","40 gallons"],"a":1,"e":"3/5 of 60 = (60 / 5) x 3 = 12 x 3 = 36 gallons."},{"q":"If a map scale is 1 inch = 25 miles, how many miles do 4 inches represent?","c":["100 miles","75 miles","29 miles","125 miles"],"a":0,"e":"4 inches x 25 miles per inch = 100 miles."},{"q":"The average of three numbers is 20. If two of the numbers are 15 and 22, what is the third?","c":["18","25","23","20"],"a":2,"e":"Sum = 20 x 3 = 60. 60 - 15 - 22 = 23. The third number is 23."},{"q":"A jacket costs $80. The sales tax is 7%. What is the total cost including tax?","c":["$85.60","$87.00","$80.70","$85.50"],"a":0,"e":"Tax = 7% of $80 = 0.07 x 80 = $5.60. Total = $80 + $5.60 = $85.60."},{"q":"A train leaves at 9:00 AM and arrives at 1:30 PM. How long was the trip?","c":["3 hours 30 minutes","4 hours","4 hours 30 minutes","5 hours"],"a":2,"e":"From 9:00 AM to 1:30 PM is 4 hours and 30 minutes."},{"q":"If 5 apples cost $2.00, how much do 12 apples cost at the same rate?","c":["$4.80","$5.00","$4.40","$6.00"],"a":0,"e":"Each apple costs $2.00 / 5 = $0.40. 12 x $0.40 = $4.80."},{"q":"What is the perimeter of a square with a side length of 7 cm?","c":["14 cm","21 cm","28 cm","49 cm"],"a":2,"e":"Perimeter of a square = 4 x side = 4 x 7 = 28 cm."},{"q":"A number increased by 12 equals 30. What is the number?","c":["42","18","22","16"],"a":1,"e":"Let the number be n. n + 12 = 30, so n = 30 - 12 = 18."},{"q":"A car uses 1 gallon of gas to travel 28 miles. How many gallons are needed to travel 196 miles?","c":["6 gallons","8 gallons","7 gallons","5 gallons"],"a":2,"e":"196 / 28 = 7 gallons needed."},{"q":"What is 0.25 written as a fraction in lowest terms?","c":["1/2","1/3","2/5","1/4"],"a":3,"e":"0.25 = 25/100 = 1/4 in lowest terms."},{"q":"A box of cereal weighs 18 ounces. How many ounces do 6 boxes weigh?","c":["108 ounces","96 ounces","120 ounces","114 ounces"],"a":0,"e":"18 x 6 = 108 ounces."},{"q":"If you save $25 each week, how much will you save in 8 weeks?","c":["$175","$200","$225","$250"],"a":1,"e":"$25 x 8 = $200."},{"q":"A pizza is cut into 8 equal slices. If 3 slices are eaten, what fraction of the pizza remains?","c":["3/8","1/2","5/8","2/3"],"a":2,"e":"8 - 3 = 5 slices remain, which is 5/8 of the pizza."},{"q":"A 5-pound bag of sugar costs $4.50. What is the cost per pound?","c":["$0.90","$1.00","$0.85","$0.80"],"a":0,"e":"$4.50 / 5 = $0.90 per pound."},{"q":"What is 3/5 of 45?","c":["15","25","27","30"],"a":2,"e":"3/5 of 45 = (45 / 5) x 3 = 9 x 3 = 27."},{"q":"A rectangle has a perimeter of 30 inches. If its width is 6 inches, what is its length?","c":["9 inches","12 inches","24 inches","15 inches"],"a":0,"e":"Perimeter = 2(L + W). 30 = 2(L + 6), so L + 6 = 15, L = 9 inches."},{"q":"A store marks up a $20 item by 30%. What is the new price?","c":["$23","$50","$26","$24"],"a":2,"e":"30% of $20 = $6. $20 + $6 = $26."},{"q":"If a runner completes a 10-kilometer race in 50 minutes, what is the average time per kilometer?","c":["6 minutes","4 minutes","10 minutes","5 minutes"],"a":3,"e":"50 minutes / 10 km = 5 minutes per kilometer."},{"q":"A class has 15 boys and 10 girls. What is the ratio of boys to girls in simplest form?","c":["2:3","5:2","3:2","15:10"],"a":2,"e":"15:10 simplifies by dividing both by 5 to get 3:2."},{"q":"What is the sum of 3/8 and 1/4?","c":["4/12","5/8","1/2","3/8"],"a":1,"e":"1/4 = 2/8. 3/8 + 2/8 = 5/8."},{"q":"A worker completes a job in 6 hours. Working at the same rate, how long to complete 4 such jobs?","c":["10 hours","18 hours","24 hours","20 hours"],"a":2,"e":"6 hours x 4 jobs = 24 hours."},{"q":"You deposit $500 in an account that earns 4% simple interest per year. How much interest do you earn in one year?","c":["$20","$40","$25","$54"],"a":0,"e":"Simple interest = $500 x 0.04 x 1 = $20."},{"q":"A bag contains 4 red marbles and 6 blue marbles. If one is drawn at random, what is the probability it is red?","c":["6/10","4/6","2/5","1/4"],"a":2,"e":"P(red) = 4 / (4 + 6) = 4/10 = 2/5."},{"q":"A car's gas tank holds 16 gallons. If gas costs $3.50 per gallon, how much to fill an empty tank?","c":["$48.00","$56.00","$52.00","$60.00"],"a":1,"e":"16 x $3.50 = $56.00."},{"q":"What is 120 divided by 8?","c":["12","14","16","15"],"a":3,"e":"120 / 8 = 15."},{"q":"A triangle has a base of 10 cm and a height of 6 cm. What is its area?","c":["60 sq cm","16 sq cm","30 sq cm","36 sq cm"],"a":2,"e":"Area of a triangle = (1/2) x base x height = (1/2) x 10 x 6 = 30 sq cm."},{"q":"If 40% of a number is 32, what is the number?","c":["80","12.8","72","128"],"a":0,"e":"0.40 x n = 32, so n = 32 / 0.40 = 80."},{"q":"A cube has edges of 3 inches. What is its volume?","c":["9 cubic inches","27 cubic inches","18 cubic inches","12 cubic inches"],"a":1,"e":"Volume of a cube = edge cubed = 3 x 3 x 3 = 27 cubic inches."},{"q":"$1,000 is invested at 5% interest compounded annually. What is the balance after 2 years?","c":["$1,100.00","$1,102.50","$1,050.00","$1,105.00"],"a":1,"e":"Year 1: $1,000 x 1.05 = $1,050. Year 2: $1,050 x 1.05 = $1,102.50."},{"q":"A recipe serves 4 people and uses 6 eggs. How many eggs are needed to serve 10 people?","c":["12 eggs","16 eggs","15 eggs","18 eggs"],"a":2,"e":"Eggs per person = 6 / 4 = 1.5. For 10 people: 1.5 x 10 = 15 eggs."},{"q":"How many feet are in 3 1/2 yards?","c":["7 feet","9 feet","10 1/2 feet","42 feet"],"a":2,"e":"1 yard = 3 feet. 3.5 x 3 = 10.5 feet, which is 10 1/2 feet."}];
QBANK["MK"] = [{"q":"What is 7 + 3 * 4 - 2?","c":["38","17","20","11"],"a":1,"e":"Order of operations: multiply first, 3*4=12. Then 7+12-2 = 17."},{"q":"Simplify: (8 - 3)^2 + 6 / 2","c":["28","22","13","16"],"a":0,"e":"Parentheses: 8-3=5, square it: 25. Then 6/2=3. 25+3 = 28."},{"q":"What is the value of 3^4?","c":["12","64","27","81"],"a":3,"e":"3^4 = 3*3*3*3 = 9*9 = 81."},{"q":"Simplify: x^5 * x^3","c":["x^8","x^15","x^2","2x^8"],"a":0,"e":"When multiplying like bases, add exponents: 5+3=8, so x^8."},{"q":"Simplify: (x^4)^3","c":["x^7","x^12","x^64","3x^4"],"a":1,"e":"Power raised to a power: multiply exponents, 4*3=12, so x^12."},{"q":"What is the square root of 144?","c":["14","16","12","24"],"a":2,"e":"12*12 = 144, so sqrt(144) = 12."},{"q":"Simplify: sqrt(50)","c":["5*sqrt(2)","2*sqrt(5)","25*sqrt(2)","10*sqrt(5)"],"a":0,"e":"50 = 25*2, sqrt(25)=5, so sqrt(50) = 5*sqrt(2)."},{"q":"Solve for x: 3x + 7 = 22","c":["3","5","15","9"],"a":1,"e":"Subtract 7: 3x=15. Divide by 3: x=5."},{"q":"Solve for x: 2(x - 4) = 10","c":["9","3","7","1"],"a":0,"e":"Distribute: 2x-8=10. Add 8: 2x=18. Divide by 2: x=9."},{"q":"Solve for x: x/4 - 3 = 2","c":["5","-4","8","20"],"a":3,"e":"Add 3: x/4=5. Multiply by 4: x=20."},{"q":"Solve the system: x + y = 10 and x - y = 4. What is x?","c":["3","6","7","8"],"a":2,"e":"Add the equations: 2x=14, so x=7 (and y=3)."},{"q":"Solve the system: 2x + y = 11 and y = x - 1. What is y?","c":["4","3","5","2"],"a":1,"e":"Substitute: 2x+(x-1)=11, so 3x=12, x=4. Then y=4-1=3."},{"q":"Solve the inequality: 2x - 5 > 7","c":["x > 1","x < 6","x > 12","x > 6"],"a":3,"e":"Add 5: 2x>12. Divide by 2: x>6."},{"q":"Solve: -3x < 9","c":["x < -3","x > -3","x < 3","x > 3"],"a":1,"e":"Divide by -3 and flip the inequality: x > -3."},{"q":"Multiply: (x + 3)(x + 5)","c":["x^2 + 8x + 15","x^2 + 15x + 8","x^2 + 8x + 8","x^2 + 15"],"a":0,"e":"FOIL: x^2 +5x+3x+15 = x^2+8x+15."},{"q":"Multiply: (x - 4)(x + 4)","c":["x^2 + 16","x^2 - 8x + 16","x^2 - 16","x^2 - 8"],"a":2,"e":"Difference of squares: (x-4)(x+4) = x^2 - 16."},{"q":"Factor: x^2 + 7x + 12","c":["(x+3)(x+4)","(x+2)(x+6)","(x+1)(x+12)","(x-3)(x-4)"],"a":0,"e":"Need two numbers multiplying to 12 and adding to 7: 3 and 4. So (x+3)(x+4)."},{"q":"Factor: x^2 - 9x + 20","c":["(x-2)(x-10)","(x-4)(x-5)","(x+4)(x+5)","(x-1)(x-20)"],"a":1,"e":"Two numbers multiplying to 20, adding to -9: -4 and -5. So (x-4)(x-5)."},{"q":"Factor completely: 6x^2 + 9x","c":["3x(2x+3)","3(2x^2+3x)","x(6x+9)","6x(x+9)"],"a":0,"e":"GCF of 6x^2 and 9x is 3x. Factor out: 3x(2x+3)."},{"q":"Solve: x^2 - 5x + 6 = 0","c":["x=-2 or x=-3","x=1 or x=6","x=2 or x=4","x=2 or x=3"],"a":3,"e":"Factor: (x-2)(x-3)=0, so x=2 or x=3."},{"q":"Solve: x^2 = 49","c":["x=7 only","x=7 or x=-7","x=24.5","x=-7 only"],"a":1,"e":"Take the square root of both sides: x = +7 or -7."},{"q":"Evaluate 2x^2 - 3x + 1 when x = 3","c":["10","19","28","8"],"a":0,"e":"2(9)-3(3)+1 = 18-9+1 = 10."},{"q":"What is the greatest common factor (GCF) of 24 and 36?","c":["6","4","12","72"],"a":2,"e":"24=2^3*3, 36=2^2*3^2. Common: 2^2*3 = 12."},{"q":"What is the least common multiple (LCM) of 6 and 8?","c":["48","24","14","2"],"a":1,"e":"6=2*3, 8=2^3. LCM = 2^3*3 = 24."},{"q":"Which of the following is a prime number?","c":["21","27","29","33"],"a":2,"e":"29 has no divisors other than 1 and 29. The others are composite (21=3*7, 27=3^3, 33=3*11)."},{"q":"The angles of a triangle are 50 degrees and 60 degrees. What is the third angle?","c":["80 degrees","70 degrees","110 degrees","60 degrees"],"a":1,"e":"Angles sum to 180. 180-50-60 = 70 degrees."},{"q":"A rectangle has length 9 and width 4. What is its area?","c":["13","26","36","45"],"a":2,"e":"Area = length * width = 9*4 = 36."},{"q":"A rectangle has length 9 and width 4. What is its perimeter?","c":["26","36","13","22"],"a":0,"e":"Perimeter = 2(l+w) = 2(9+4) = 2*13 = 26."},{"q":"What is the area of a triangle with base 10 and height 6?","c":["60","16","20","30"],"a":3,"e":"Area = (1/2)*base*height = (1/2)*10*6 = 30."},{"q":"A circle has radius 5. What is its area? (use pi)","c":["10*pi","25*pi","5*pi","50*pi"],"a":1,"e":"Area = pi*r^2 = pi*5^2 = 25*pi."},{"q":"A circle has radius 7. What is its circumference? (use pi)","c":["14*pi","49*pi","7*pi","21*pi"],"a":0,"e":"Circumference = 2*pi*r = 2*pi*7 = 14*pi."},{"q":"A right triangle has legs 6 and 8. What is the hypotenuse?","c":["14","10","48","12"],"a":1,"e":"Pythagorean: c^2 = 6^2+8^2 = 36+64 = 100, so c = 10."},{"q":"A right triangle has a hypotenuse of 13 and one leg of 5. What is the other leg?","c":["8","12","18","144"],"a":1,"e":"Leg^2 = 13^2 - 5^2 = 169-25 = 144, so leg = 12."},{"q":"What is the volume of a cube with edge length 4?","c":["16","12","48","64"],"a":3,"e":"Volume = side^3 = 4^3 = 64."},{"q":"What is the volume of a rectangular box 3 by 4 by 5?","c":["12","60","47","120"],"a":1,"e":"Volume = l*w*h = 3*4*5 = 60."},{"q":"What is the surface area of a cube with edge length 3?","c":["27","9","54","36"],"a":2,"e":"Surface area = 6*side^2 = 6*9 = 54."},{"q":"What is the slope of the line through points (1, 2) and (4, 11)?","c":["3","9/5","1/3","13/5"],"a":0,"e":"Slope = (11-2)/(4-1) = 9/3 = 3."},{"q":"What is the distance between points (0, 0) and (3, 4)?","c":["7","5","12","25"],"a":1,"e":"Distance = sqrt(3^2+4^2) = sqrt(9+16) = sqrt(25) = 5."},{"q":"What is the midpoint of the segment from (2, 4) to (8, 10)?","c":["(5, 7)","(6, 6)","(10, 14)","(3, 3)"],"a":0,"e":"Midpoint = ((2+8)/2, (4+10)/2) = (5, 7)."},{"q":"In a right triangle, the side opposite a 30 degree angle is 5 and the hypotenuse is 10. What is sin(30 degrees)?","c":["2","1/2","5/3","sqrt(3)/2"],"a":1,"e":"sin = opposite/hypotenuse = 5/10 = 1/2."}];
QBANK["WK"] = [{"q":"Abundant most nearly means:","c":["plentiful","scarce","hidden","fragile"],"a":0,"e":"Abundant means existing in large quantities; plentiful is the synonym."},{"q":"The witness gave a candid account of the accident. Candid most nearly means:","c":["fearful","frank","lengthy","biased"],"a":1,"e":"Candid means honest and straightforward; frank is the synonym."},{"q":"Diminish most nearly means:","c":["repair","confuse","decrease","gather"],"a":2,"e":"Diminish means to make or become smaller; decrease is the synonym."},{"q":"Vital most nearly means:","c":["optional","ancient","quiet","essential"],"a":3,"e":"Vital means absolutely necessary; essential is the synonym."},{"q":"The instructions were ambiguous and confused the recruits. Ambiguous most nearly means:","c":["unclear","detailed","forceful","helpful"],"a":0,"e":"Ambiguous means open to more than one meaning; unclear is the synonym."},{"q":"Conceal most nearly means:","c":["reveal","hide","destroy","carry"],"a":1,"e":"Conceal means to keep from sight; hide is the synonym."},{"q":"Rigid most nearly means:","c":["smooth","heavy","stiff","empty"],"a":2,"e":"Rigid means unable to bend; stiff is the synonym."},{"q":"Novice most nearly means:","c":["expert","leader","traveler","beginner"],"a":3,"e":"A novice is a person new to something; beginner is the synonym."},{"q":"The general's tactics were prudent and avoided needless losses. Prudent most nearly means:","c":["reckless","cautious","cruel","sudden"],"a":1,"e":"Prudent means showing careful good judgment; cautious is the synonym."},{"q":"Terminate most nearly means:","c":["begin","end","extend","repeat"],"a":1,"e":"Terminate means to bring to an end; end is the synonym."},{"q":"Fatigue most nearly means:","c":["tiredness","hunger","fear","boredom"],"a":0,"e":"Fatigue means extreme tiredness; tiredness is the synonym."},{"q":"Vacant most nearly means:","c":["crowded","locked","empty","dusty"],"a":2,"e":"Vacant means not occupied; empty is the synonym."},{"q":"The soldier remained vigilant throughout the long night. Vigilant most nearly means:","c":["sleepy","cheerful","silent","watchful"],"a":3,"e":"Vigilant means keeping careful watch; watchful is the synonym."},{"q":"Obstinate most nearly means:","c":["flexible","stubborn","generous","timid"],"a":1,"e":"Obstinate means refusing to change one's mind; stubborn is the synonym."},{"q":"Sufficient most nearly means:","c":["enough","extra","rare","cheap"],"a":0,"e":"Sufficient means as much as is needed; enough is the synonym."},{"q":"Hostile most nearly means:","c":["friendly","curious","unfriendly","calm"],"a":2,"e":"Hostile means showing strong opposition or dislike; unfriendly is the synonym."},{"q":"The coach offered a concise summary of the plan. Concise most nearly means:","c":["wordy","brief","confusing","loud"],"a":1,"e":"Concise means giving information clearly and in few words; brief is the synonym."},{"q":"Hazardous most nearly means:","c":["safe","useful","sturdy","dangerous"],"a":3,"e":"Hazardous means risky; dangerous is the synonym."},{"q":"Reluctant most nearly means:","c":["eager","unwilling","quick","honest"],"a":1,"e":"Reluctant means hesitant to do something; unwilling is the synonym."},{"q":"Tedious most nearly means:","c":["boring","exciting","brief","easy"],"a":0,"e":"Tedious means long and tiresome; boring is the synonym."},{"q":"The new policy will augment the unit's resources. Augment most nearly means:","c":["reduce","increase","replace","ignore"],"a":1,"e":"Augment means to make larger; increase is the synonym."},{"q":"Frail most nearly means:","c":["bold","wide","weak","loud"],"a":2,"e":"Frail means weak and delicate; weak is the synonym."},{"q":"Genuine most nearly means:","c":["fake","cheap","rare","real"],"a":3,"e":"Genuine means truly what it is said to be; real is the synonym."},{"q":"Summit most nearly means:","c":["base","peak","valley","slope"],"a":1,"e":"Summit means the highest point; peak is the synonym."},{"q":"The mechanic gave a meticulous inspection of the engine. Meticulous most nearly means:","c":["thorough","careless","hasty","brief"],"a":0,"e":"Meticulous means showing great attention to detail; thorough is the synonym."},{"q":"Initiate most nearly means:","c":["finish","begin","delay","cancel"],"a":1,"e":"Initiate means to start; begin is the synonym."},{"q":"Pungent most nearly means:","c":["bland","sweet","sharp","faint"],"a":2,"e":"Pungent means having a strong, sharp smell or taste; sharp is the synonym."},{"q":"Lenient most nearly means:","c":["strict","angry","fair","merciful"],"a":3,"e":"Lenient means not harsh in punishment; merciful is the synonym."},{"q":"The river was placid in the early morning. Placid most nearly means:","c":["stormy","calm","muddy","rapid"],"a":1,"e":"Placid means calm and peaceful; calm is the synonym."},{"q":"Deteriorate most nearly means:","c":["worsen","improve","clean","build"],"a":0,"e":"Deteriorate means to become worse; worsen is the synonym."},{"q":"Adjacent most nearly means:","c":["distant","neighboring","opposite","hidden"],"a":1,"e":"Adjacent means next to or near; neighboring is the synonym."},{"q":"Scrutinize most nearly means:","c":["glance","ignore","examine","approve"],"a":2,"e":"Scrutinize means to examine closely; examine is the synonym."},{"q":"The crowd grew boisterous after the win. Boisterous most nearly means:","c":["quiet","tired","polite","rowdy"],"a":3,"e":"Boisterous means noisy and energetic; rowdy is the synonym."},{"q":"Feasible most nearly means:","c":["possible","costly","unlikely","required"],"a":0,"e":"Feasible means able to be done; possible is the synonym."},{"q":"Mundane most nearly means:","c":["thrilling","ordinary","rare","sacred"],"a":1,"e":"Mundane means dull and commonplace; ordinary is the synonym."},{"q":"Vindicate most nearly means:","c":["accuse","punish","clear","doubt"],"a":2,"e":"Vindicate means to clear of blame; clear is the synonym."},{"q":"The recruit showed remarkable tenacity during training. Tenacity most nearly means:","c":["laziness","talent","fear","persistence"],"a":3,"e":"Tenacity means determination and persistence; persistence is the synonym."},{"q":"Arid most nearly means:","c":["dry","cold","fertile","windy"],"a":0,"e":"Arid means having little rainfall; dry is the synonym."},{"q":"Benevolent most nearly means:","c":["cruel","kind","wealthy","strict"],"a":1,"e":"Benevolent means well meaning and kindly; kind is the synonym."},{"q":"Fluctuate most nearly means:","c":["stabilize","stop","vary","rise"],"a":2,"e":"Fluctuate means to rise and fall irregularly; vary is the synonym."},{"q":"The judge issued a stern warning. Stern most nearly means:","c":["gentle","brief","unclear","severe"],"a":3,"e":"Stern means strict and serious; severe is the synonym."},{"q":"Abolish most nearly means:","c":["create","eliminate","enforce","delay"],"a":1,"e":"Abolish means to do away with formally; eliminate is the synonym."},{"q":"Eloquent most nearly means:","c":["articulate","awkward","quiet","rude"],"a":0,"e":"Eloquent means fluent and persuasive in speech; articulate is the synonym."},{"q":"Imminent most nearly means:","c":["distant","approaching","unlikely","past"],"a":1,"e":"Imminent means about to happen; approaching is the synonym."},{"q":"The trail was treacherous after the storm. Treacherous most nearly means:","c":["smooth","scenic","dangerous","narrow"],"a":2,"e":"Treacherous means hazardous and unsafe; dangerous is the synonym."},{"q":"Apprehensive most nearly means:","c":["confident","curious","tired","anxious"],"a":3,"e":"Apprehensive means worried that something bad will happen; anxious is the synonym."},{"q":"Resilient most nearly means:","c":["fragile","tough","heavy","slow"],"a":1,"e":"Resilient means able to recover quickly; tough is the synonym."},{"q":"The proposal received unanimous support. Unanimous most nearly means:","c":["united","divided","reluctant","partial"],"a":0,"e":"Unanimous means agreed by everyone; united is the synonym."},{"q":"Squander most nearly means:","c":["save","waste","earn","share"],"a":1,"e":"Squander means to spend wastefully; waste is the synonym."},{"q":"Verify most nearly means:","c":["doubt","reject","confirm","guess"],"a":2,"e":"Verify means to check the truth of something; confirm is the synonym."}];
QBANK["PC"] = [{"q":"Passage: Honeybees communicate the location of food through a movement known as the waggle dance. By moving in a figure-eight pattern and vibrating its body, a returning bee tells the others both the direction and the distance of a flower patch. The angle of the dance relative to the sun points the way, while the length of the waggle indicates how far the food is.\n\nQuestion: What is the main idea of this passage?","c":["Honeybees use a waggle dance to share the location of food","Honeybees prefer flowers that grow near the hive","The sun controls when honeybees leave the hive","Bees vibrate their bodies only to stay warm"],"a":0,"e":"The passage opens by stating bees communicate food location through the waggle dance and the rest describes how, making this the main idea."},{"q":"Passage: Honeybees communicate the location of food through a movement known as the waggle dance. By moving in a figure-eight pattern and vibrating its body, a returning bee tells the others both the direction and the distance of a flower patch. The angle of the dance relative to the sun points the way, while the length of the waggle indicates how far the food is.\n\nQuestion: According to the passage, what does the length of the waggle indicate?","c":["The size of the flower patch","The number of bees in the hive","How far away the food is","The time of day"],"a":2,"e":"The passage states the length of the waggle indicates how far the food is."},{"q":"Passage: Honeybees communicate the location of food through a movement known as the waggle dance. By moving in a figure-eight pattern and vibrating its body, a returning bee tells the others both the direction and the distance of a flower patch. The angle of the dance relative to the sun points the way, while the length of the waggle indicates how far the food is.\n\nQuestion: It can be inferred from the passage that without the sun as a reference, a watching bee would most likely have trouble determining the:","c":["distance to the food","direction to the food","number of flowers","color of the flowers"],"a":1,"e":"The passage says the angle of the dance relative to the sun points the way (direction), so losing the sun reference would affect determining direction."},{"q":"Passage: In the early 1800s, lighthouse keepers lived isolated lives along rocky coasts. Their main duty was to keep the lamp burning every night so that passing ships could avoid the dangerous shoreline. A keeper had to trim the wick, refill the oil, and polish the glass lenses, often climbing the tower several times before dawn.\n\nQuestion: What was the lighthouse keeper's main duty?","c":["To rescue sailors from sinking ships","To keep the lamp burning every night","To map the rocky coastline","To deliver mail to nearby towns"],"a":1,"e":"The passage states the keeper's main duty was to keep the lamp burning every night."},{"q":"Passage: In the early 1800s, lighthouse keepers lived isolated lives along rocky coasts. Their main duty was to keep the lamp burning every night so that passing ships could avoid the dangerous shoreline. A keeper had to trim the wick, refill the oil, and polish the glass lenses, often climbing the tower several times before dawn.\n\nQuestion: As used in the passage, the word \"isolated\" most nearly means:","c":["wealthy","crowded","cut off from others","constantly traveling"],"a":2,"e":"The passage describes keepers living alone along remote rocky coasts, so isolated means cut off from others."},{"q":"Passage: In the early 1800s, lighthouse keepers lived isolated lives along rocky coasts. Their main duty was to keep the lamp burning every night so that passing ships could avoid the dangerous shoreline. A keeper had to trim the wick, refill the oil, and polish the glass lenses, often climbing the tower several times before dawn.\n\nQuestion: It can be inferred from the passage that the keeper's work was:","c":["demanding and repetitive","mostly done during daylight","shared by a large crew","easy and relaxing"],"a":0,"e":"The passage lists repeated chores and notes the keeper often climbed the tower several times before dawn, implying demanding, repetitive work."},{"q":"Passage: When a new employee joins our department, we assign each one a mentor for the first month. The mentor answers questions, explains office procedures, and introduces the newcomer to coworkers. We have found that workers who receive this guidance settle into their roles far more quickly than those left to figure things out alone.\n\nQuestion: According to the passage, how long is a new employee assigned a mentor?","c":["For one week","For the first month","For one year","Until they request a transfer"],"a":1,"e":"The passage states each new employee is assigned a mentor for the first month."},{"q":"Passage: When a new employee joins our department, we assign each one a mentor for the first month. The mentor answers questions, explains office procedures, and introduces the newcomer to coworkers. We have found that workers who receive this guidance settle into their roles far more quickly than those left to figure things out alone.\n\nQuestion: What is the author's main point about the mentoring program?","c":["Mentors are paid extra for their work","New employees rarely ask questions","Guidance helps new workers adjust faster","Most coworkers dislike meeting newcomers"],"a":2,"e":"The passage concludes that workers who receive this guidance settle into their roles far more quickly, the author's main point."},{"q":"Passage: When a new employee joins our department, we assign each one a mentor for the first month. The mentor answers questions, explains office procedures, and introduces the newcomer to coworkers. We have found that workers who receive this guidance settle into their roles far more quickly than those left to figure things out alone.\n\nQuestion: The author's attitude toward the mentoring program can best be described as:","c":["doubtful","approving","indifferent","alarmed"],"a":1,"e":"The author credits the program with helping workers settle in faster, showing an approving attitude."},{"q":"Passage: Recycling aluminum cans saves a remarkable amount of energy. Producing a new can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore. Because of this, a single recycled can can power a television for several hours' worth of saved energy.\n\nQuestion: According to the passage, making a can from recycled aluminum uses about what fraction of the energy of making one from raw ore?","c":["Five percent","Fifty percent","Ninety percent","One hundred percent"],"a":0,"e":"The passage states producing a can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore."},{"q":"Passage: Recycling aluminum cans saves a remarkable amount of energy. Producing a new can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore. Because of this, a single recycled can can power a television for several hours' worth of saved energy.\n\nQuestion: What is the main idea of this passage?","c":["Aluminum cans are difficult to recycle","Recycling aluminum cans saves a great deal of energy","Televisions use very little electricity","Raw ore is cheaper than recycled aluminum"],"a":1,"e":"The opening sentence states recycling aluminum cans saves a remarkable amount of energy, which the rest supports."},{"q":"Passage: Recycling aluminum cans saves a remarkable amount of energy. Producing a new can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore. Because of this, a single recycled can can power a television for several hours' worth of saved energy.\n\nQuestion: It can be inferred from the passage that making aluminum from raw ore is:","c":["far more energy-intensive than recycling","slightly cheaper than recycling","done only in small factories","better for the environment"],"a":0,"e":"Since recycling uses only five percent of the energy of raw ore production, it follows that making aluminum from raw ore is far more energy-intensive."},{"q":"Passage: The desert may look lifeless during the heat of the day, but it comes alive after dark. Many animals, such as kangaroo rats and certain owls, are nocturnal, sleeping in burrows or shade while the sun is high. They emerge at night to hunt and forage when cooler temperatures make moving around far less dangerous.\n\nQuestion: As used in the passage, the word \"nocturnal\" most nearly means:","c":["active at night","unable to see","living underground forever","afraid of water"],"a":0,"e":"The passage explains these animals sleep during the day and emerge at night, so nocturnal means active at night."},{"q":"Passage: The desert may look lifeless during the heat of the day, but it comes alive after dark. Many animals, such as kangaroo rats and certain owls, are nocturnal, sleeping in burrows or shade while the sun is high. They emerge at night to hunt and forage when cooler temperatures make moving around far less dangerous.\n\nQuestion: According to the passage, why do these desert animals come out at night?","c":["Because there is more food at night","Because cooler temperatures make moving around less dangerous","Because they cannot sleep in burrows","Because other animals chase them away by day"],"a":1,"e":"The passage states they emerge at night when cooler temperatures make moving around far less dangerous."},{"q":"Passage: The desert may look lifeless during the heat of the day, but it comes alive after dark. Many animals, such as kangaroo rats and certain owls, are nocturnal, sleeping in burrows or shade while the sun is high. They emerge at night to hunt and forage when cooler temperatures make moving around far less dangerous.\n\nQuestion: What is the main idea of the passage?","c":["Kangaroo rats are the most common desert animal","The desert has no plants","Deserts are too hot for any life to survive","The desert is full of life that is active mainly at night"],"a":3,"e":"The passage contrasts the seemingly lifeless daytime desert with nighttime activity, making the main idea that desert life is active mainly at night."},{"q":"Passage: Before refrigeration was common, people preserved food by salting, drying, or smoking it. These methods removed moisture or created conditions in which bacteria could not easily grow. A barrel of salted fish or a string of dried peppers could last through an entire winter, allowing families to eat well long after the harvest had ended.\n\nQuestion: According to the passage, why did salting and drying help preserve food?","c":["They added flavor that people enjoyed","They removed moisture or created conditions where bacteria could not easily grow","They kept food frozen solid","They made food lighter to carry"],"a":1,"e":"The passage states these methods removed moisture or created conditions in which bacteria could not easily grow."},{"q":"Passage: Before refrigeration was common, people preserved food by salting, drying, or smoking it. These methods removed moisture or created conditions in which bacteria could not easily grow. A barrel of salted fish or a string of dried peppers could last through an entire winter, allowing families to eat well long after the harvest had ended.\n\nQuestion: It can be inferred from the passage that, without these methods, much food would have:","c":["tasted better","lasted even longer","spoiled before it could be eaten","been easier to transport"],"a":2,"e":"Since the methods prevented bacterial growth and let food last through winter, without them food would likely have spoiled before being eaten."},{"q":"Passage: Before refrigeration was common, people preserved food by salting, drying, or smoking it. These methods removed moisture or created conditions in which bacteria could not easily grow. A barrel of salted fish or a string of dried peppers could last through an entire winter, allowing families to eat well long after the harvest had ended.\n\nQuestion: Which of the following is given as an example of preserved food in the passage?","c":["Fresh milk","A string of dried peppers","A bowl of soup","A loaf of warm bread"],"a":1,"e":"The passage names a string of dried peppers as an example of food that could last through the winter."}];
QBANK["EI"] = [{"q":"What is the unit of electrical resistance?","c":["Volt","Ampere","Ohm","Watt"],"a":2,"e":"Resistance is measured in ohms. The volt measures voltage, the ampere measures current, and the watt measures power."},{"q":"According to Ohm's law, what voltage is required to push 2 amps through a 10-ohm resistor?","c":["5 V","12 V","20 V","0.2 V"],"a":2,"e":"V = I * R = 2 A * 10 ohms = 20 V."},{"q":"A 120-volt source drives a current through a 60-ohm resistor. What is the current?","c":["0.5 A","2 A","180 A","7200 A"],"a":1,"e":"I = V / R = 120 V / 60 ohms = 2 A."},{"q":"What is the total resistance of two 100-ohm resistors connected in series?","c":["50 ohms","100 ohms","150 ohms","200 ohms"],"a":3,"e":"In series, resistances add: 100 + 100 = 200 ohms."},{"q":"What is the total resistance of two 100-ohm resistors connected in parallel?","c":["50 ohms","100 ohms","150 ohms","200 ohms"],"a":0,"e":"For two equal parallel resistors, total = R/2 = 100/2 = 50 ohms."},{"q":"How much power is dissipated by a device that draws 3 amps at 12 volts?","c":["4 W","15 W","36 W","9 W"],"a":2,"e":"P = V * I = 12 V * 3 A = 36 W."},{"q":"Which of the following is the best electrical conductor?","c":["Rubber","Copper","Glass","Plastic"],"a":1,"e":"Copper is an excellent conductor and is widely used in wiring. Rubber, glass, and plastic are insulators."},{"q":"Which material is commonly used as an electrical insulator?","c":["Silver","Aluminum","Rubber","Gold"],"a":2,"e":"Rubber is an insulator that resists current flow. Silver, aluminum, and gold are good conductors."},{"q":"What does AC stand for in electricity?","c":["Active Current","Alternating Current","Ampere Charge","Applied Capacitance"],"a":1,"e":"AC stands for alternating current, in which the direction of current flow periodically reverses."},{"q":"In a DC circuit, the current flows in which manner?","c":["In one constant direction","Reversing 60 times per second","Only through capacitors","In a circular magnetic loop"],"a":0,"e":"DC (direct current) flows in one constant direction, such as from a battery."},{"q":"What is the unit of frequency?","c":["Farad","Henry","Hertz","Joule"],"a":2,"e":"Frequency is measured in hertz (Hz), which equals cycles per second."},{"q":"Standard household AC power in the United States has a frequency of:","c":["50 Hz","60 Hz","120 Hz","240 Hz"],"a":1,"e":"U.S. household AC is delivered at 60 Hz (60 cycles per second)."},{"q":"Which component stores energy in an electric field and opposes changes in voltage?","c":["Resistor","Capacitor","Inductor","Diode"],"a":1,"e":"A capacitor stores energy in an electric field between its plates and opposes sudden voltage changes."},{"q":"Which component allows current to flow in only one direction?","c":["Resistor","Capacitor","Diode","Inductor"],"a":2,"e":"A diode permits current to flow in one direction and blocks it in the reverse direction."},{"q":"What is the unit of capacitance?","c":["Henry","Farad","Ohm","Hertz"],"a":1,"e":"Capacitance is measured in farads (F)."},{"q":"An inductor stores energy in what form?","c":["Electric field","Magnetic field","Chemical bonds","Heat"],"a":1,"e":"An inductor (coil) stores energy in the magnetic field created by current flowing through it."},{"q":"A transformer is used primarily to:","c":["Store electrical charge","Convert AC voltage from one level to another","Rectify AC into DC","Amplify a signal"],"a":1,"e":"A transformer changes AC voltage levels (step up or step down) using electromagnetic induction between coils."},{"q":"A step-up transformer has:","c":["More turns on the primary than the secondary","More turns on the secondary than the primary","Equal turns on both windings","No primary winding"],"a":1,"e":"A step-up transformer has more turns on the secondary coil, increasing the output voltage."},{"q":"Which device is commonly used to amplify electrical signals or act as a switch?","c":["Resistor","Capacitor","Transistor","Fuse"],"a":2,"e":"A transistor can amplify signals or switch current, and is a fundamental building block of electronics."},{"q":"What is the total voltage of three 1.5-volt batteries connected in series?","c":["1.5 V","3 V","4.5 V","0.5 V"],"a":2,"e":"Series cells add their voltages: 1.5 + 1.5 + 1.5 = 4.5 V."},{"q":"In a series circuit, the current is:","c":["Different in each component","The same through all components","Zero everywhere","Highest at the source only"],"a":1,"e":"In a series circuit there is only one path, so the same current flows through every component."},{"q":"In a parallel circuit, the voltage across each branch is:","c":["The same across all branches","Divided equally among branches","Zero","Always increasing"],"a":0,"e":"Branches in parallel share the same two nodes, so each branch has the same voltage."},{"q":"How much current flows through a 240-ohm resistor connected across a 12-volt battery?","c":["0.05 A","2 A","20 A","0.5 A"],"a":0,"e":"I = V / R = 12 V / 240 ohms = 0.05 A."},{"q":"A semiconductor's conductivity is:","c":["Always zero","Greater than a metal's","Between that of a conductor and an insulator","Infinite"],"a":2,"e":"Semiconductors such as silicon conduct better than insulators but worse than conductors, and their conductivity can be controlled."},{"q":"What is the purpose of grounding an electrical system?","c":["To increase voltage","To provide a safe path for fault current","To store extra charge","To raise the frequency"],"a":1,"e":"Grounding provides a low-resistance safe path for fault current to flow to earth, protecting people and equipment."},{"q":"The unit of electric current is the:","c":["Volt","Ampere","Ohm","Coulomb"],"a":1,"e":"Current is measured in amperes (amps). The coulomb measures charge, not current rate."},{"q":"What is the power dissipated by a 4-ohm resistor carrying 3 amps?","c":["12 W","36 W","7 W","48 W"],"a":1,"e":"P = I^2 * R = 3^2 * 4 = 9 * 4 = 36 W."},{"q":"Which color band on a resistor represents the digit 0 in the standard color code?","c":["Brown","Black","Red","Gold"],"a":1,"e":"In the resistor color code, black = 0, brown = 1, red = 2."},{"q":"A fuse protects a circuit by:","c":["Increasing the current","Melting and opening the circuit during overcurrent","Storing excess voltage","Converting AC to DC"],"a":1,"e":"A fuse contains a thin wire that melts when current exceeds its rating, breaking the circuit to prevent damage."},{"q":"What happens to total resistance when more resistors are added in parallel?","c":["It increases","It decreases","It stays the same","It becomes infinite"],"a":1,"e":"Adding parallel paths gives current more routes, so total resistance decreases below the smallest resistor."},{"q":"The resistance of two 6-ohm resistors in parallel is:","c":["3 ohms","6 ohms","12 ohms","2 ohms"],"a":0,"e":"For two equal parallel resistors, total = R/2 = 6/2 = 3 ohms."},{"q":"A material through which electric current flows easily is called a:","c":["Insulator","Conductor","Dielectric","Resistor"],"a":1,"e":"A conductor allows electric current to flow easily because it has many free electrons."},{"q":"What voltage is across a 5-ohm resistor that dissipates 80 watts of power?","c":["16 V","20 V","400 V","4 V"],"a":1,"e":"P = V^2 / R, so V = sqrt(P * R) = sqrt(80 * 5) = sqrt(400) = 20 V."},{"q":"Around a wire carrying current, what is created?","c":["An electric charge only","A magnetic field","A vacuum","Static electricity only"],"a":1,"e":"A current-carrying conductor produces a magnetic field around it; this is the basis of electromagnetism."},{"q":"What is 1 kilovolt equal to?","c":["10 volts","100 volts","1000 volts","0.001 volts"],"a":2,"e":"The prefix kilo means 1000, so 1 kilovolt = 1000 volts."}];
QBANK["GS"] = [{"q":"Which organelle is known as the powerhouse of the cell because it produces most of the cell's ATP?","c":["Mitochondrion","Ribosome","Golgi apparatus","Lysosome"],"a":0,"e":"Mitochondria carry out cellular respiration, generating most of the cell's ATP energy."},{"q":"In humans, which type of blood cell is primarily responsible for fighting infection?","c":["Red blood cells","White blood cells","Platelets","Plasma cells only"],"a":1,"e":"White blood cells (leukocytes) are the main components of the immune system that fight infection."},{"q":"What is the basic structural and functional unit of all living organisms?","c":["The atom","The tissue","The organ","The cell"],"a":3,"e":"The cell is the smallest unit that can carry out all life processes; all organisms are made of cells."},{"q":"Which process do green plants use to convert sunlight, water, and carbon dioxide into glucose?","c":["Respiration","Photosynthesis","Fermentation","Transpiration"],"a":1,"e":"Photosynthesis uses light energy to convert CO2 and water into glucose and oxygen."},{"q":"Genetic information in cells is primarily stored in molecules of:","c":["DNA","ATP","RNA polymerase","Glucose"],"a":0,"e":"DNA (deoxyribonucleic acid) carries the hereditary instructions in the form of genes."},{"q":"Which organ system is primarily responsible for pumping blood throughout the body?","c":["Respiratory system","Circulatory system","Digestive system","Nervous system"],"a":1,"e":"The circulatory (cardiovascular) system, centered on the heart, pumps blood through the body."},{"q":"An organism that makes its own food is called a:","c":["Consumer","Decomposer","Producer","Parasite"],"a":2,"e":"Producers, such as plants, make their own food through photosynthesis and form the base of food chains."},{"q":"In which part of the human body does most nutrient absorption occur?","c":["Stomach","Esophagus","Large intestine","Small intestine"],"a":3,"e":"The small intestine, with its large surface area of villi, absorbs most digested nutrients."},{"q":"A trait controlled by an allele that is expressed only when two copies are present is called:","c":["Dominant","Recessive","Codominant","Mutant"],"a":1,"e":"A recessive trait is masked by a dominant allele and appears only when both alleles are recessive."},{"q":"Which of the following is the correct order, from smallest to largest, of biological organization?","c":["Organ, tissue, cell, organism","Tissue, cell, organism, organ","Cell, tissue, organ, organism","Cell, organ, tissue, organism"],"a":2,"e":"Cells form tissues, tissues form organs, and organs work together in an organism."},{"q":"The gas that humans inhale and that is essential for cellular respiration is:","c":["Carbon dioxide","Oxygen","Nitrogen","Helium"],"a":1,"e":"Oxygen is taken in during breathing and used by cells to release energy in respiration."},{"q":"Which kingdom includes organisms such as mushrooms, molds, and yeasts?","c":["Plantae","Animalia","Protista","Fungi"],"a":3,"e":"Fungi are a separate kingdom of organisms that absorb nutrients and include mushrooms, molds, and yeasts."},{"q":"What is the chemical symbol for sodium?","c":["So","Na","Sd","S"],"a":1,"e":"Sodium's symbol Na comes from its Latin name natrium."},{"q":"The smallest particle of an element that retains the properties of that element is the:","c":["Atom","Molecule","Electron","Proton"],"a":0,"e":"An atom is the smallest unit of an element that still has that element's chemical properties."},{"q":"Which subatomic particle carries a negative electric charge?","c":["Proton","Neutron","Electron","Nucleus"],"a":2,"e":"Electrons carry a negative charge; protons are positive and neutrons are neutral."},{"q":"On the pH scale, a solution with a pH of 3 is considered:","c":["Strongly basic","Neutral","Acidic","Pure water"],"a":2,"e":"A pH below 7 is acidic; pH 7 is neutral and above 7 is basic."},{"q":"What is the chemical formula for water?","c":["CO2","H2O","O2","NaCl"],"a":1,"e":"Water is made of two hydrogen atoms and one oxygen atom, giving the formula H2O."},{"q":"When a substance changes directly from a solid to a gas without becoming a liquid, the process is called:","c":["Condensation","Evaporation","Melting","Sublimation"],"a":3,"e":"Sublimation is the phase change from solid directly to gas, as seen with dry ice."},{"q":"In the periodic table, elements in the same vertical column are called a:","c":["Period","Series","Group","Shell"],"a":2,"e":"A group (or family) is a vertical column of elements that share similar chemical properties."},{"q":"Which of the following is a chemical change rather than a physical change?","c":["Melting ice","Rusting iron","Boiling water","Crushing a can"],"a":1,"e":"Rusting forms a new substance (iron oxide), making it a chemical change; the others are physical."},{"q":"Table salt is a compound formed from sodium and which other element?","c":["Carbon","Calcium","Potassium","Chlorine"],"a":3,"e":"Table salt is sodium chloride (NaCl), composed of sodium and chlorine."},{"q":"The number of protons in the nucleus of an atom is called its:","c":["Atomic number","Mass number","Valence number","Isotope number"],"a":0,"e":"The atomic number equals the number of protons and identifies the element."},{"q":"Which state of matter has a definite volume but takes the shape of its container?","c":["Solid","Gas","Liquid","Plasma"],"a":2,"e":"Liquids keep a fixed volume but flow to take the shape of whatever holds them."},{"q":"In a chemical equation, the substances that react together are called the:","c":["Products","Reactants","Catalysts","Solvents"],"a":1,"e":"Reactants are the starting substances; products are what is formed by the reaction."},{"q":"A substance that speeds up a chemical reaction without being used up is a:","c":["Catalyst","Solute","Reactant","Precipitate"],"a":0,"e":"A catalyst increases reaction rate and is not consumed in the reaction."},{"q":"According to Newton's first law of motion, an object in motion will:","c":["Stay in motion unless acted on by a force","Slow down and stop on its own","Speed up without any force","Always move in a circle"],"a":0,"e":"Newton's first law (inertia) states an object keeps its motion unless an outside force acts on it."},{"q":"The unit used to measure force in the SI system is the:","c":["Joule","Watt","Newton","Pascal"],"a":2,"e":"Force is measured in newtons (N); a joule is energy and a watt is power."},{"q":"Energy stored in an object because of its position or height is called:","c":["Kinetic energy","Potential energy","Thermal energy","Electrical energy"],"a":1,"e":"Potential energy is stored energy due to position, such as a raised object's gravitational potential energy."},{"q":"Which of these is an example of a simple machine?","c":["A lever","A car engine","A computer","A battery"],"a":0,"e":"A lever is one of the six classic simple machines used to change force or motion."},{"q":"In physics, work is done when:","c":["An object is held still","An object stays at rest","A force is applied with no movement","A force moves an object a distance"],"a":3,"e":"Work equals force times distance; no work is done if there is no movement in the force's direction."},{"q":"The speed of light in a vacuum is approximately:","c":["300 kilometers per second","3,000 meters per second","300,000 kilometers per second","30 meters per second"],"a":2,"e":"Light travels at about 300,000 km/s (3 x 10^8 meters per second) in a vacuum."},{"q":"What happens to the boiling point of water as altitude increases?","c":["It stays the same","It increases","It decreases","It becomes zero"],"a":2,"e":"Lower air pressure at high altitude lets water boil at a lower temperature."},{"q":"Which of the following best describes acceleration?","c":["The total distance traveled","The rate of change of velocity","A constant speed","The force of gravity"],"a":1,"e":"Acceleration is how quickly velocity changes over time, including changes in speed or direction."},{"q":"In an electric circuit, the unit of electrical resistance is the:","c":["Volt","Ohm","Ampere","Watt"],"a":1,"e":"Resistance is measured in ohms; volts measure voltage and amperes measure current."},{"q":"Sound travels fastest through which of the following?","c":["A vacuum","Air","Water","Steel"],"a":3,"e":"Sound moves fastest through dense solids like steel and cannot travel through a vacuum."},{"q":"Newton's third law of motion states that for every action there is:","c":["No reaction","A larger reaction","An equal and opposite reaction","A delayed reaction"],"a":2,"e":"Newton's third law says forces come in pairs that are equal in size and opposite in direction."},{"q":"Which color of visible light has the longest wavelength?","c":["Blue","Green","Violet","Red"],"a":3,"e":"Red light has the longest wavelength of visible light; violet has the shortest."},{"q":"Which planet is closest to the Sun?","c":["Mercury","Venus","Earth","Mars"],"a":0,"e":"Mercury is the innermost planet, orbiting closest to the Sun."},{"q":"The process by which water vapor in the air turns into liquid water is called:","c":["Evaporation","Condensation","Precipitation","Sublimation"],"a":1,"e":"Condensation is the change of water vapor to liquid, as when clouds or dew form."},{"q":"The outermost layer of the Earth, on which we live, is called the:","c":["Mantle","Outer core","Crust","Inner core"],"a":2,"e":"The crust is the thin, solid outermost layer of the Earth above the mantle."},{"q":"Igneous rock is formed by the:","c":["Cementing of sediment","Heat and pressure on existing rock","Erosion of mountains","Cooling and hardening of magma or lava"],"a":3,"e":"Igneous rock forms when molten magma or lava cools and solidifies."},{"q":"Which layer of the atmosphere contains the ozone layer and is where most weather occurs below it?","c":["Stratosphere","Mesosphere","Thermosphere","Exosphere"],"a":0,"e":"The stratosphere holds the ozone layer; the troposphere below it is where most weather occurs."},{"q":"Approximately what percentage of the Earth's surface is covered by water?","c":["About 30 percent","About 70 percent","About 50 percent","About 90 percent"],"a":1,"e":"Water covers roughly 70 percent of Earth's surface, mostly in the oceans."},{"q":"What causes the regular rise and fall of ocean tides?","c":["Wind patterns","The gravitational pull of the Moon and Sun","Underwater volcanoes","Changes in water temperature"],"a":1,"e":"Tides are caused mainly by the Moon's gravity, with the Sun also contributing."},{"q":"A scientist who studies the weather and atmosphere is called a:","c":["Geologist","Astronomer","Seismologist","Meteorologist"],"a":3,"e":"Meteorologists study weather and atmospheric conditions; geologists study rocks and astronomers study space."}];
QBANK["MC"] = [{"q":"A lever has its fulcrum 2 ft from a 100 lb load and 8 ft from the point where effort is applied. How much effort is needed to balance the load?","c":["25 lb","50 lb","100 lb","400 lb"],"a":0,"e":"For a balanced lever, load x load-arm = effort x effort-arm. So 100 lb x 2 ft = effort x 8 ft, giving effort = 200/8 = 25 lb."},{"q":"What is the mechanical advantage of a machine that uses 20 lb of effort to lift a 100 lb load?","c":["2","5","20","80"],"a":1,"e":"Mechanical advantage = output force / input force = 100 lb / 20 lb = 5."},{"q":"How much work is done lifting a 50 lb box straight up a height of 4 ft?","c":["12.5 ft-lb","54 ft-lb","200 ft-lb","2000 ft-lb"],"a":2,"e":"Work = force x distance = 50 lb x 4 ft = 200 ft-lb."},{"q":"A single fixed pulley is used to lift a load. What is its main advantage?","c":["It doubles the force applied","It changes the direction of the force","It halves the distance the rope must move","It eliminates friction"],"a":1,"e":"A single fixed pulley has a mechanical advantage of 1; it does not multiply force but changes the direction of the applied force, letting you pull down to lift up."},{"q":"Two gears mesh together. The driver gear has 10 teeth and the driven gear has 30 teeth. If the driver turns at 60 rpm, how fast does the driven gear turn?","c":["180 rpm","60 rpm","30 rpm","20 rpm"],"a":3,"e":"Gear speeds are inversely proportional to teeth. Driven speed = driver speed x (driver teeth / driven teeth) = 60 x (10/30) = 20 rpm."},{"q":"Pressure is defined as:","c":["Force multiplied by area","Force divided by area","Force multiplied by distance","Mass divided by volume"],"a":1,"e":"Pressure = force / area. A given force spread over a smaller area produces greater pressure."},{"q":"A hydraulic system has a small piston of area 2 sq in and a large piston of area 10 sq in. A force of 50 lb is applied to the small piston. What force is produced at the large piston?","c":["10 lb","50 lb","250 lb","500 lb"],"a":2,"e":"By Pascal's principle pressure is equal: F1/A1 = F2/A2. So F2 = 50 lb x (10/2) = 250 lb."},{"q":"An inclined plane is 12 ft long and rises 3 ft. What is its ideal mechanical advantage?","c":["4","3","9","36"],"a":0,"e":"For an inclined plane, IMA = length of slope / height = 12 ft / 3 ft = 4."},{"q":"Which simple machine is essentially an inclined plane wrapped around a cylinder?","c":["Wedge","Pulley","Screw","Lever"],"a":2,"e":"A screw is an inclined plane wrapped around a central shaft; the threads form the spiral ramp."},{"q":"A wheelbarrow is an example of which class of lever?","c":["First-class","Second-class","Third-class","Fourth-class"],"a":1,"e":"In a wheelbarrow the load is between the fulcrum (wheel) and the effort (handles), which defines a second-class lever."},{"q":"Torque is best described as:","c":["A pushing force in a straight line","The turning effect of a force about a pivot","The energy stored in a spring","The resistance to sliding motion"],"a":1,"e":"Torque is the rotational or turning effect of a force, equal to force times the perpendicular distance from the pivot (torque = force x lever arm)."},{"q":"A force of 30 lb is applied at the end of a wrench 2 ft long, perpendicular to the handle. What torque is produced about the bolt?","c":["15 ft-lb","32 ft-lb","60 ft-lb","120 ft-lb"],"a":2,"e":"Torque = force x lever arm = 30 lb x 2 ft = 60 ft-lb."},{"q":"Which type of friction is generally greatest for the same surfaces?","c":["Rolling friction","Kinetic (sliding) friction","Static friction","Fluid friction"],"a":2,"e":"Static friction (which must be overcome to start motion) is typically greater than kinetic friction, and rolling friction is usually the smallest."},{"q":"A block-and-tackle system supports a load with 4 strands of rope. What is its ideal mechanical advantage?","c":["1","2","4","8"],"a":2,"e":"The ideal mechanical advantage of a pulley system equals the number of rope strands supporting the load, here 4."},{"q":"Which of the following has the most potential energy?","c":["A 10 lb weight resting on the ground","A 10 lb weight held 5 ft above the ground","A 10 lb weight held 2 ft above the ground","A 10 lb weight sliding on the floor"],"a":1,"e":"Gravitational potential energy = weight x height. The greatest height (5 ft) gives the most potential energy."},{"q":"Water is densest and exerts the greatest pressure at which point in a tank?","c":["At the surface","Halfway down","At the bottom","Pressure is equal everywhere"],"a":2,"e":"Liquid pressure increases with depth because of the weight of the water above, so it is greatest at the bottom."},{"q":"A 200 lb load is lifted using a machine with a mechanical advantage of 4. Ignoring friction, how much effort force is required?","c":["50 lb","100 lb","200 lb","800 lb"],"a":0,"e":"MA = load / effort, so effort = load / MA = 200 lb / 4 = 50 lb."},{"q":"Two children sit on a seesaw. A 60 lb child sits 4 ft from the pivot. How far from the pivot must a 40 lb child sit to balance it?","c":["3 ft","4 ft","6 ft","8 ft"],"a":2,"e":"Balance requires equal torques: 60 lb x 4 ft = 40 lb x d, so d = 240/40 = 6 ft."},{"q":"As a moving object's speed increases, its kinetic energy:","c":["Decreases","Stays the same","Increases","Becomes zero"],"a":2,"e":"Kinetic energy = 1/2 x mass x velocity squared. Increasing speed increases kinetic energy (and it rises with the square of velocity)."},{"q":"Which arrangement of a board ramp makes it easiest to push a heavy barrel up to a fixed height?","c":["A shorter, steeper ramp","A longer, more gradual ramp","Both require the same effort","A vertical lift"],"a":1,"e":"A longer ramp increases the mechanical advantage (slope length / height), reducing the effort force needed, though over a longer distance."},{"q":"A spring stretches 2 in when a 10 lb weight hangs from it. How far will it stretch with a 25 lb weight, assuming it obeys Hooke's law?","c":["2 in","4 in","5 in","10 in"],"a":2,"e":"Hooke's law: stretch is proportional to force. The spring stretches 0.2 in per lb (2 in / 10 lb), so 25 lb x 0.2 = 5 in."},{"q":"Momentum of a moving object is calculated as:","c":["Mass divided by velocity","Mass times velocity","Mass times acceleration","Force times time squared"],"a":1,"e":"Momentum = mass x velocity. A heavier or faster object has more momentum."},{"q":"A wheel-and-axle has a wheel radius of 12 in and an axle radius of 3 in. What is its ideal mechanical advantage?","c":["3","4","9","36"],"a":1,"e":"For a wheel and axle, IMA = wheel radius / axle radius = 12 / 3 = 4."},{"q":"In a first-class lever, the fulcrum is located:","c":["Between the effort and the load","At the same point as the load","Beyond the effort","Between two loads"],"a":0,"e":"A first-class lever (like a seesaw or pliers) has the fulcrum positioned between the effort and the load."},{"q":"If you press a thumbtack, the sharp point pushes into the wood more easily than the flat head pushes into your thumb because:","c":["The point has a larger area","The point concentrates the force over a smaller area","The head receives more force","Wood is softer than skin"],"a":1,"e":"Pressure = force / area. The small point area produces very high pressure from the same force, while the wide head spreads force over a large area."},{"q":"A 100 lb crate is dragged 10 ft across a floor against a friction force of 30 lb. How much work is done against friction?","c":["70 ft-lb","130 ft-lb","300 ft-lb","1000 ft-lb"],"a":2,"e":"Work against friction = friction force x distance = 30 lb x 10 ft = 300 ft-lb."},{"q":"Which statement about a machine's mechanical advantage and the distance traveled is true?","c":["Greater force output requires greater input distance","Greater force output requires shorter input distance","Force and distance are unrelated in machines","Machines create energy to gain force"],"a":0,"e":"Machines trade force for distance; to multiply force you must apply the effort over a greater distance, since work in equals work out (ignoring friction)."},{"q":"Two gears are meshed. The driver gear turns clockwise. The single gear directly meshed with it turns:","c":["Clockwise","Counterclockwise","It does not turn","In random directions"],"a":1,"e":"Directly meshed gears rotate in opposite directions, so a clockwise driver turns the meshed gear counterclockwise."},{"q":"An object floats in water when:","c":["Its weight is greater than the buoyant force","Its weight equals the buoyant force","It has no mass","It is heavier than water of equal volume"],"a":1,"e":"An object floats when the upward buoyant force equals its weight; this happens when it is less dense than the fluid, displacing enough fluid to support it."},{"q":"A 3 lb object and a 6 lb object are dropped from the same height in a vacuum. Which hits the ground first?","c":["The 3 lb object","The 6 lb object","They hit at the same time","Neither falls in a vacuum"],"a":2,"e":"In a vacuum there is no air resistance, so all objects fall with the same acceleration due to gravity and reach the ground at the same time."},{"q":"Increasing the diameter of a hydraulic output piston (while keeping the input the same) will:","c":["Decrease the output force","Increase the output force","Have no effect on force","Reduce the system pressure"],"a":1,"e":"Output force = pressure x area. A larger output piston has more area, so for the same pressure it produces a greater output force."},{"q":"A pendulum swings back and forth. At the lowest point of its swing, it has the most:","c":["Potential energy","Kinetic energy","Friction","Mass"],"a":1,"e":"At the lowest point the pendulum moves fastest, so kinetic energy is greatest and potential energy is least; energy converts between the two."},{"q":"A nutcracker uses two handles joined at a hinge to crack a nut placed near the hinge. This is an example of:","c":["A third-class lever","A second-class lever","A wheel and axle","A pulley"],"a":1,"e":"With the hinge as the fulcrum and the nut (load) between the fulcrum and the hand effort, the nutcracker acts as a second-class lever, multiplying force."},{"q":"Which change would increase the friction between two surfaces?","c":["Adding oil between them","Polishing both surfaces smooth","Pressing the surfaces together harder","Adding rollers underneath"],"a":2,"e":"Friction increases with the normal force pressing the surfaces together; pressing harder increases friction. Lubricants and smoothing reduce it."},{"q":"A gear with 40 teeth drives a gear with 8 teeth. What is the gear ratio of driver to driven, and does the small gear turn faster or slower?","c":["5 to 1, faster","1 to 5, slower","5 to 1, slower","1 to 1, same speed"],"a":0,"e":"Gear ratio = driver teeth / driven teeth = 40/8 = 5 to 1. The smaller driven gear turns 5 times for each turn of the driver, so it turns faster."}];
